import{_ as n,o as a,c as o,a4 as i}from"./chunks/framework.lC8lx-25.js";const h=JSON.parse('{"title":"ADR-001: ESM-only, zero runtime dependencies","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-001-esm-zero-dependency.md","filePath":"reference/decisions/ADR-001-esm-zero-dependency.md"}'),t={name:"reference/decisions/ADR-001-esm-zero-dependency.md"};function r(s,e,l,d,c,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-001-esm-only-zero-runtime-dependencies" tabindex="-1">ADR-001: ESM-only, zero runtime dependencies <a class="header-anchor" href="#adr-001-esm-only-zero-runtime-dependencies" aria-label="Permalink to &quot;ADR-001: ESM-only, zero runtime dependencies&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: RD-01 (scaffolding &amp; toolchain), reaffirmed by RD-10 (non-functional)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>A terminal SDK foundation ships to many environments and must be trustworthy at the supply-chain level. Two early choices shape everything downstream: the module system, and how much third-party code runs at runtime.</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><h3 id="option-a-dual-cjs-esm-allow-runtime-deps-as-needed" tabindex="-1">Option A: Dual CJS+ESM, allow runtime deps as needed <a class="header-anchor" href="#option-a-dual-cjs-esm-allow-runtime-deps-as-needed" aria-label="Permalink to &quot;Option A: Dual CJS+ESM, allow runtime deps as needed&quot;">​</a></h3><ul><li><strong>Pros</strong>: Broadest consumer compatibility; reuse existing terminal libraries.</li><li><strong>Cons</strong>: Dual-build complexity; every runtime dep is attack surface, audit burden, and a potential native-build/install failure.</li></ul><h3 id="option-b-esm-only-zero-runtime-dependencies-pure-js-node-built-ins-only" tabindex="-1">Option B: ESM-only, zero runtime dependencies (pure-JS, Node built-ins only) <a class="header-anchor" href="#option-b-esm-only-zero-runtime-dependencies-pure-js-node-built-ins-only" aria-label="Permalink to &quot;Option B: ESM-only, zero runtime dependencies (pure-JS, Node built-ins only)&quot;">​</a></h3><ul><li><strong>Pros</strong>: Minimal attack surface; clean installs on all platforms (no node-gyp); forces a well-factored pure core; trivial to audit.</li><li><strong>Cons</strong>: No CommonJS <code>require()</code>; must re-implement primitives instead of pulling a library.</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Chosen option</strong>: Option B — the package is ESM-only and ships with zero runtime dependencies, using only Node built-ins.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The foundation&#39;s value is correctness and trustworthiness, not breadth of features borrowed from npm. Zero runtime deps makes the runtime surface auditable to the Node standard library, guarantees clean cross-platform installs, and pressures the design toward pure, testable functions. ESM-only matches the modern Node baseline (≥ 18) and avoids dual-build complexity. The choice is enforced by <code>npm run check:deps</code> (fails on any native runtime dep) and the RD-01 packaging spec (<code>sideEffects:false</code>, <code>.d.ts</code>, <code>engines.node&gt;=18</code>).</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Auditably small runtime surface; <code>npm audit</code> stays clean.</li><li>Tree-shakeable (<code>sideEffects:false</code>), verified by the RD-10 esbuild check.</li><li>Clean installs everywhere — no compile step.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>CommonJS consumers must use dynamic <code>import()</code>.</li><li>Primitives (width tables, colour math) are implemented in-repo rather than borrowed.</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>A future genuine need for a runtime dep would require a license/audit guard (tracked as RD-10 DEF-2) before it ships.</li></ul>',20)])])}const m=n(t,[["render",r]]);export{h as __pageData,m as default};
